import React from 'react';
import { NavLink, useNavigate } from 'react-router-dom';
import { useAuth } from '../../context/AuthContext';
import {
  User, Users, Calendar, FileText, BarChart2,
  LogOut, Settings
} from 'lucide-react';

const navByRole = {
  ENTREPRENEUR: [
    { to: '/dashboard',     icon: BarChart2,  label: 'Tableau de bord' },
    { to: '/profile',       icon: User,        label: 'Mon profil'       },
    { to: '/events',        icon: Calendar,    label: 'Événements'       },
    { to: '/publications',  icon: FileText,    label: 'Publications'     },
  ],
  COMMUNITY_MANAGER: [
    { to: '/cm/dashboard',      icon: BarChart2, label: 'Tableau de bord'   },
    { to: '/cm/profiles',       icon: Users,     label: 'Profils en attente' },
    { to: '/cm/publications',   icon: FileText,  label: 'Modération'         },
    { to: '/cm/events',         icon: Calendar,  label: 'Événements'         },
    { to: '/cm/scoring',        icon: Settings,  label: 'Grille de scoring'  },
  ],
  FUND_MANAGER: [
    { to: '/fund/dashboard', icon: BarChart2, label: 'Tableau de bord' },
    { to: '/fund/startups',  icon: Users,     label: 'Startups'        },
  ],
  MENTOR: [
    { to: '/mentor/events',       icon: Calendar,  label: 'Mes webinars'     },
    { to: '/mentor/deliverables', icon: FileText,  label: 'Livrables'        },
  ],
};

export default function Layout({ children }) {
  const { user, logout, hasRole } = useAuth();
  const navigate = useNavigate();

  const role = user?.roles?.[0]?.replace('ROLE_', '') || 'ENTREPRENEUR';
  const navItems = navByRole[role] || navByRole.ENTREPRENEUR;

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  return (
    <div style={{ display: 'flex', minHeight: '100vh' }}>
      {/* Sidebar */}
      <aside style={{
        width: 240,
        background: 'var(--color-ink)',
        color: 'white',
        display: 'flex',
        flexDirection: 'column',
        flexShrink: 0,
      }}>
        {/* Brand */}
        <div style={{ padding: '28px 24px 20px' }}>
          <div style={{
            display: 'flex',
            alignItems: 'center',
            gap: 10,
            marginBottom: 4,
          }}>
            <div style={{
              width: 32, height: 32,
              background: 'var(--color-brand)',
              borderRadius: 6,
              display: 'flex', alignItems: 'center', justifyContent: 'center',
              fontWeight: 900, fontSize: 14, color: 'white'
            }}>A</div>
            <span style={{ fontFamily: 'var(--font-display)', fontSize: 16, fontWeight: 700 }}>
              Growth Engine
            </span>
          </div>
          <div style={{ fontSize: 11, opacity: 0.45, letterSpacing: '0.06em', textTransform: 'uppercase', paddingLeft: 42 }}>
            {role.replace('_', ' ')}
          </div>
        </div>

        <div style={{ height: 1, background: 'rgba(255,255,255,0.08)', margin: '0 16px 12px' }} />

        {/* Nav */}
        <nav style={{ flex: 1, padding: '0 12px' }}>
          {navItems.map(({ to, icon: Icon, label }) => (
            <NavLink
              key={to}
              to={to}
              style={({ isActive }) => ({
                display: 'flex',
                alignItems: 'center',
                gap: 10,
                padding: '10px 12px',
                borderRadius: 8,
                marginBottom: 2,
                fontSize: 14,
                fontWeight: isActive ? 600 : 400,
                color: isActive ? 'white' : 'rgba(255,255,255,0.55)',
                background: isActive ? 'rgba(200, 16, 46, 0.25)' : 'transparent',
                textDecoration: 'none',
                transition: 'all 0.15s',
              })}
            >
              <Icon size={17} />
              {label}
            </NavLink>
          ))}
        </nav>

        {/* User + Logout */}
        <div style={{ padding: '16px 12px', borderTop: '1px solid rgba(255,255,255,0.08)' }}>
          <div style={{ padding: '8px 12px', marginBottom: 4 }}>
            <div style={{ fontSize: 13, fontWeight: 600 }}>
              {user?.firstName} {user?.lastName}
            </div>
            <div style={{ fontSize: 11, opacity: 0.45, marginTop: 2 }}>{user?.email}</div>
          </div>
          <button
            onClick={handleLogout}
            style={{
              display: 'flex', alignItems: 'center', gap: 8,
              width: '100%', padding: '8px 12px',
              background: 'transparent', border: 'none',
              color: 'rgba(255,255,255,0.45)', fontSize: 13,
              cursor: 'pointer', borderRadius: 6,
              transition: 'color 0.15s',
            }}
            onMouseEnter={e => e.currentTarget.style.color = 'white'}
            onMouseLeave={e => e.currentTarget.style.color = 'rgba(255,255,255,0.45)'}
          >
            <LogOut size={15} />
            Déconnexion
          </button>
        </div>
      </aside>

      {/* Main content */}
      <main style={{ flex: 1, overflow: 'auto', background: 'var(--color-surface)' }}>
        {children}
      </main>
    </div>
  );
}
